import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-17","description":"","frontmatter":{"title":"The Decoder — 2026-05-17","date":"2026-05-17T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-17-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-17-the-decoder.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-17-the-decoder.md"};function s(l,e,i,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="🔓-the-decoder-—-2026-05-17" tabindex="-1">🔓 The Decoder — 2026-05-17 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-17" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-17&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="new-benchmark-shows-claude-mythos-and-gpt-5-5-can-develop-real-browser-exploits-autonomously" tabindex="-1"><a href="https://the-decoder.com/new-benchmark-shows-claude-mythos-and-gpt-5-5-can-develop-real-browser-exploits-autonomously/" target="_blank" rel="noreferrer">New benchmark shows Claude Mythos and GPT-5.5 can develop real browser exploits autonomously</a> <a class="header-anchor" href="#new-benchmark-shows-claude-mythos-and-gpt-5-5-can-develop-real-browser-exploits-autonomously" aria-label="Permalink to &quot;[New benchmark shows Claude Mythos and GPT-5.5 can develop real browser exploits autonomously](https://the-decoder.com/new-benchmark-shows-claude-mythos-and-gpt-5-5-can-develop-real-browser-exploits-autonomously/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-16</em></p><p>Researchers at Carnegie Mellon University built a new benchmark that measures how far AI agents can go when exploiting real vulnerabilities in Google&#39;s V8 engine. Mythos leads GPT-5.5 by a wide margin but costs twelve times as much.</p><p>The article <a href="https://the-decoder.com/new-benchmark-shows-claude-mythos-and-gpt-5-5-can-develop-real-browser-exploits-autonomously/" target="_blank" rel="noreferrer">New benchmark shows Claude Mythos and GPT-5.5 can develop real browser exploits autonomously</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="youtube-opens-its-deepfake-face-swap-detection-tool-to-all-adult-creators" tabindex="-1"><a href="https://the-decoder.com/youtube-opens-its-deepfake-face-swap-detection-tool-to-all-adult-creators/" target="_blank" rel="noreferrer">YouTube opens its deepfake face-swap detection tool to all adult creators</a> <a class="header-anchor" href="#youtube-opens-its-deepfake-face-swap-detection-tool-to-all-adult-creators" aria-label="Permalink to &quot;[YouTube opens its deepfake face-swap detection tool to all adult creators](https://the-decoder.com/youtube-opens-its-deepfake-face-swap-detection-tool-to-all-adult-creators/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-16</em></p><p>YouTube is opening its Likeness Detection tool to all creators 18 and older. The system spots AI-generated face fakes in other users&#39; videos and lets creators file removal requests directly through YouTube Studio. Until now, the feature was limited to partner program members; now it&#39;s meant to protect smaller channels too.</p><p>The article <a href="https://the-decoder.com/youtube-opens-its-deepfake-face-swap-detection-tool-to-all-adult-creators/" target="_blank" rel="noreferrer">YouTube opens its deepfake face-swap detection tool to all adult creators</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="new-benchmark-confirms-ai-video-generators-look-stunning-but-still-can-t-reason-about-the-world" tabindex="-1"><a href="https://the-decoder.com/new-benchmark-confirms-ai-video-generators-look-stunning-but-still-cant-reason-about-the-world/" target="_blank" rel="noreferrer">New benchmark confirms AI video generators look stunning but still can&#39;t reason about the world</a> <a class="header-anchor" href="#new-benchmark-confirms-ai-video-generators-look-stunning-but-still-can-t-reason-about-the-world" aria-label="Permalink to &quot;[New benchmark confirms AI video generators look stunning but still can&#39;t reason about the world](https://the-decoder.com/new-benchmark-confirms-ai-video-generators-look-stunning-but-still-cant-reason-about-the-world/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-16</em></p><p>A new benchmark called WorldReasonBench tests video generators not on image quality, but on physical and logical plausibility. ByteDance&#39;s Seedance 2.0 leads the field ahead of Veo 3.1 and Sora 2, with commercial models scoring roughly twice as high as open-source alternatives. Logical reasoning remains the hardest category for every model by a wide margin. The jump from pixel generator to actual world model still hasn&#39;t happened.</p><p>The article <a href="https://the-decoder.com/new-benchmark-confirms-ai-video-generators-look-stunning-but-still-cant-reason-about-the-world/" target="_blank" rel="noreferrer">New benchmark confirms AI video generators look stunning but still can&#39;t reason about the world</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="openai-bought-a-voice-cloning-startup-famous-for-celebrity-imitations" tabindex="-1"><a href="https://the-decoder.com/openai-bought-a-voice-cloning-startup-famous-for-celebrity-imitations/" target="_blank" rel="noreferrer">OpenAI bought a voice cloning startup famous for celebrity imitations</a> <a class="header-anchor" href="#openai-bought-a-voice-cloning-startup-famous-for-celebrity-imitations" aria-label="Permalink to &quot;[OpenAI bought a voice cloning startup famous for celebrity imitations](https://the-decoder.com/openai-bought-a-voice-cloning-startup-famous-for-celebrity-imitations/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-16</em></p><p>OpenAI has acquired Weights.gg, a small startup that let users create and share AI voice clones of celebrities like Taylor Swift and Donald Trump. The team of around six now works at OpenAI, but the company doesn&#39;t plan to release a standalone cloning product.</p><p>The article <a href="https://the-decoder.com/openai-bought-a-voice-cloning-startup-famous-for-celebrity-imitations/" target="_blank" rel="noreferrer">OpenAI bought a voice cloning startup famous for celebrity imitations</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="for-1-3-million-a-month-openclaw-founder-peter-steinberger-runs-100-ai-agents-that-code-review-prs-and-find-bugs" tabindex="-1"><a href="https://the-decoder.com/for-1-3-million-a-month-openclaw-founder-peter-steinberger-runs-100-ai-agents-that-code-review-prs-and-find-bugs/" target="_blank" rel="noreferrer">For $1.3 million a month, OpenClaw founder Peter Steinberger runs 100 AI agents that code, review PRs, and find bugs</a> <a class="header-anchor" href="#for-1-3-million-a-month-openclaw-founder-peter-steinberger-runs-100-ai-agents-that-code-review-prs-and-find-bugs" aria-label="Permalink to &quot;[For $1.3 million a month, OpenClaw founder Peter Steinberger runs 100 AI agents that code, review PRs, and find bugs](https://the-decoder.com/for-1-3-million-a-month-openclaw-founder-peter-steinberger-runs-100-ai-agents-that-code-review-prs-and-find-bugs/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-16</em></p><p>A three-person team led by Peter Steinberger keeps about 100 Codex instances running for the open-source project OpenClaw, driving OpenAI API spend to $1.3 million a month. Steinberger frames the bill as a research investment: he wants to see what software development looks like when token costs don&#39;t matter.</p><p>The article <a href="https://the-decoder.com/for-1-3-million-a-month-openclaw-founder-peter-steinberger-runs-100-ai-agents-that-code-review-prs-and-find-bugs/" target="_blank" rel="noreferrer">For $1.3 million a month, OpenClaw founder Peter Steinberger runs 100 AI agents that code, review PRs, and find bugs</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
